import{_ as a,o,c as r,ag as l}from"./chunks/framework.D2Ob5GRY.js";const v=JSON.parse('{"title":"环境变量概览","description":"","frontmatter":{},"headers":[],"relativePath":"deployment/env-vars-overview.md","filePath":"deployment/env-vars-overview.md"}'),d={name:"deployment/env-vars-overview.md"};function i(c,e,t,n,s,_){return o(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="环境变量概览" tabindex="-1">环境变量概览 <a class="header-anchor" href="#环境变量概览" aria-label="Permalink to &quot;环境变量概览&quot;">​</a></h1><blockquote><p>账号、LLM、端口与路径等常用环境变量说明；完整列表见参考手册。</p></blockquote><h2 id="账号配置变量-linscio-username-password" tabindex="-1">账号配置变量（LINSCIO_USERNAME / PASSWORD） <a class="header-anchor" href="#账号配置变量-linscio-username-password" aria-label="Permalink to &quot;账号配置变量（LINSCIO_USERNAME / PASSWORD）&quot;">​</a></h2><ul><li><code>LINSCIO_USERNAME</code>：门户注册的账号（用于 container-token 路径）。</li><li><code>LINSCIO_PASSWORD</code>：门户账号密码。</li><li>与授权码二选一：若使用 <code>LINSCIO_LICENSE_KEY</code>，则可不填账号密码。</li></ul><h2 id="llm-配置变量-各-provider-的-api-key-和代理" tabindex="-1">LLM 配置变量（各 Provider 的 API Key 和代理） <a class="header-anchor" href="#llm-配置变量-各-provider-的-api-key-和代理" aria-label="Permalink to &quot;LLM 配置变量（各 Provider 的 API Key 和代理）&quot;">​</a></h2><ul><li><code>OPENAI_API_KEY</code>、<code>DEEPSEEK_API_KEY</code>、<code>DASHSCOPE_API_KEY</code>、<code>GEMINI_API_KEY</code> 等：对应服务商的 API Key。</li><li><code>PROXY_URL</code> / <code>HTTPS_PROXY</code> / <code>HTTP_PROXY</code>：代理地址，用于访问海外 API。</li></ul><h2 id="端口与路径配置" tabindex="-1">端口与路径配置 <a class="header-anchor" href="#端口与路径配置" aria-label="Permalink to &quot;端口与路径配置&quot;">​</a></h2><ul><li><code>DATA_DIR</code>：数据目录，默认 <code>/app/data</code>（Docker 内）。</li><li><code>CONFIG_DIR</code>：配置目录，默认 <code>DATA_DIR/config</code>。</li><li>端口由 docker-compose 或启动命令指定，默认 8080。</li></ul><h2 id="env-文件模板" tabindex="-1">.env 文件模板 <a class="header-anchor" href="#env-文件模板" aria-label="Permalink to &quot;.env 文件模板&quot;">​</a></h2><p>复制项目根目录 <code>.env.example</code> 为 <code>.env</code>，按需填写上述变量；完整参考见 <a href="/docs/reference/env-vars.html">环境变量完整参考表</a>。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/deployment/llm-providers.html">LLM 服务商配置详解</a></li><li><a href="/docs/reference/env-vars.html">环境变量完整参考表</a></li></ul>',12)])])}const P=a(d,[["render",i]]);export{v as __pageData,P as default};
